#!/bin/bash
# MongoDB Replica Set Status and Health Check
set -euo pipefail

RS_PRIMARY="localhost:27017"

echo "=== Replica Set Configuration ==="
mongosh --port 27017 --quiet --eval "
const config = rs.conf();
print('Replica Set: ' + config._id);
config.members.forEach(m => {
  print('  ' + m.host + ' (priority: ' + m.priority + ', votes: ' + m.votes + ')');
});
"

echo ""
echo "=== Member Status ==="
mongosh --port 27017 --quiet --eval "
const status = rs.status();
status.members.forEach(m => {
  const lag = m.optimeDate ? (status.date - m.optimeDate) / 1000 : 'N/A';
  print(m.name + ': ' + m.stateStr + ' | health: ' + m.health + ' | lag: ' + lag + 's');
});
"

echo ""
echo "=== Replication Lag Detail ==="
mongosh --port 27017 --quiet --eval "rs.printSecondaryReplicationInfo()"

echo ""
echo "=== Oplog Size ==="
mongosh --port 27017 --quiet --eval "
const oplog = db.getSiblingDB('local').oplog.rs.stats();
print('Size: ' + Math.round(oplog.size / 1024 / 1024) + 'MB');
print('Max Size: ' + Math.round(oplog.maxSize / 1024 / 1024) + 'MB');
print('Docs: ' + oplog.count);
"

echo ""
echo "=== Connection String ==="
mongosh --port 27017 --quiet --eval "
const config = rs.conf();
const hosts = config.members.map(m => m.host).join(',');
print('mongodb://' + hosts + '/mydb?replicaSet=' + config._id);
"
